# PyInstaller + multiprocessing/process pools:
# When using ProcessPoolExecutor in a frozen onefile app on Windows, child processes
# are spawned by re-launching the same executable. Without freeze_support(), the
# child process can incorrectly run the GUI entrypoint and open another window.
try:
    import multiprocessing
    if getattr(sys, "frozen", False):
        multiprocessing.freeze_support()
except Exception:
    pass

# In PyInstaller --windowed builds there is no console, so stdout/stderr can be None.
# Redirect them to a file early so all existing safe_print() debug output is preserved.
def _runtime_log_dir() -> str:
    """
    Central runtime log directory.
    Use LocalAppData for both installed and dev runs to avoid packaging stale src/logs.
    """
    app_data = os.environ.get("LOCALAPPDATA", "C:\\")
    return os.path.join(app_data, "RAWviewer", "logs")


def _redirect_stdio_to_file_if_needed():
    try:
        # Opt-in only: do not create log folders/files in normal releases.
        if os.environ.get("RAWVIEWER_REDIRECT_STDIO", "").strip() not in ("1", "true", "True", "YES", "yes"):
            return

        is_frozen = bool(getattr(sys, "frozen", False))
        if not is_frozen:
            return
        if sys.stdout is not None and sys.stderr is not None:
            return

        log_dir = _runtime_log_dir()
        try:
            os.makedirs(log_dir, exist_ok=True)
        except OSError:
            return

        from datetime import datetime

        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        path = os.path.join(log_dir, f"rawviewer_console_{ts}.log")
        f = open(path, "a", encoding="utf-8", buffering=1)  # line-buffered
        if sys.stdout is None:
            sys.stdout = f
        if sys.stderr is None:
            sys.stderr = f
    except Exception:
        # Never fail startup due to debug output plumbing
        pass

_redirect_stdio_to_file_if_needed()


def _enable_fatal_crash_dump_if_needed():
    """
    Enable low-level fatal crash dumps (access violation/segfault) very early.
    This catches crashes that bypass Python exception handlers.
    """
    try:
        if os.environ.get("RAWVIEWER_FATAL_DUMP", "1").strip().lower() in ("0", "false", "no", "off"):
            return
        import signal
        import faulthandler
        from datetime import datetime

        dump_dir = _runtime_log_dir()
        try:
            os.makedirs(dump_dir, exist_ok=True)
        except OSError:
            return

        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        dump_path = os.path.join(dump_dir, f"fatal_dump_{ts}.log")
        f = open(dump_path, "a", encoding="utf-8", buffering=1)
        faulthandler.enable(file=f, all_threads=True)
        faulthandler.register(signal.SIGABRT, file=f, all_threads=True)
    except Exception:
        # Never block startup due to diagnostics setup.
        pass


_enable_fatal_crash_dump_if_needed()

# Force unbuffered output for Windows console
# Note: In PyInstaller --windowed builds, sys.stdout/stderr may be None
if sys.platform == 'win32':
    if sys.stdout is not None:
        try:
            sys.stdout.reconfigure(encoding='utf-8', errors='replace')
        except (AttributeError, OSError):
            pass  # stdout may not support reconfigure in some environments
    if sys.stderr is not None:
        try:
            sys.stderr.reconfigure(encoding='utf-8', errors='replace')
        except (AttributeError, OSError):
            pass  # stderr may not support reconfigure in some environments

# Safe print function for PyInstaller --windowed builds
# In windowed mode, sys.stdout/stderr may be None
def _env_true(name: str, default: bool = False) -> bool:
    raw = os.environ.get(name)
    if raw is None:
        return default
    return str(raw).strip().lower() in {"1", "true", "yes", "on"}


def _env_int(name: str, default: int, *, minimum: int = 0) -> int:
    try:
        return max(minimum, int(os.environ.get(name, str(default)).strip()))
    except (TypeError, ValueError):
        return default


def _is_primary_process() -> bool:
    try:
        import multiprocessing
        return multiprocessing.current_process().name == "MainProcess"
    except Exception:
        return True


_VERBOSE_CONSOLE = _env_true("RAWVIEWER_VERBOSE_CONSOLE", default=False)


def safe_print(*args, **kwargs):
    """Safely print to stdout, handling None case in windowed builds"""
    force = bool(kwargs.pop("force", False))
    if not force and (not _VERBOSE_CONSOLE or not _is_primary_process()):
        return
    if sys.stdout is not None:
        try:
            print(*args, **kwargs)
        except (OSError, AttributeError):
            pass  # stdout may not be available

def safe_print_err(*args, **kwargs):
    """Safely print to stderr, handling None case in windowed builds"""
    _ = kwargs.pop("force", False)
    if sys.stderr is not None:
        try:
            print(*args, file=sys.stderr, **kwargs)
        except (OSError, AttributeError):
            pass  # stderr may not be available


def _norm_path(p: str) -> str:
    """Normalize paths for reliable equality checks on Windows."""
    try:
        if not p:
            return ""
        # normcase handles case-insensitivity on Windows; normpath normalizes slashes.
        return os.path.normcase(os.path.normpath(p))
    except Exception:
        return p or ""


def _find_file_index_in_list(files, file_path, *, default: int = -1) -> int:
    """Return index of *file_path* in *files* (normcase/abspath/basename), or *default*."""
    if not files or not file_path:
        return default
    target_norm = _norm_path(file_path)
    try:
        target_abs = os.path.normcase(os.path.abspath(file_path))
    except (OSError, TypeError):
        target_abs = target_norm
    target_base = os.path.normcase(os.path.basename(file_path))
    for i, fp in enumerate(files):
        if not fp:
            continue
        if _norm_path(fp) == target_norm:
            return i
        try:
            if os.path.normcase(os.path.abspath(fp)) == target_abs:
                return i
        except (OSError, TypeError):
            pass
        if os.path.normcase(os.path.basename(fp)) == target_base:
            return i
    return default


def _share_logger() -> logging.Logger:
    return logging.getLogger("rawviewer.share")


def _share_log(
    level: int,
    msg: str,
    *args,
    exc_info: bool = False,
) -> None:
    """Dedicated share diagnostics (always prefixed; visible at INFO in console)."""
    _share_logger().log(level, "[SHARE] " + msg, *args, exc_info=exc_info)


def _macos_share_items_array(url) -> object:
    """Build AppKit items array (NSURL). Empty/invalid arrays make picker spin forever."""
    if url is None:
        return None
    try:
        from Foundation import NSArray

        arr = NSArray.arrayWithArray_([url])
        if arr is None:
            _share_log(logging.WARNING, "NSArray.arrayWithArray_ returned None")
            return None
        try:
            count = int(arr.count())
        except Exception:
            count = len(arr) if hasattr(arr, "__len__") else 0
        if count < 1:
            _share_log(logging.WARNING, "share items array count=0")
            return None
        return arr
    except Exception as exc:
        _share_log(logging.WARNING, "NSArray build failed: %s", exc)
        return None


_macos_share_picker_delegate_cls = None
_macos_sharing_service_delegate_cls = None


def _macos_write_sharing_content_scope(scope, value: int = 0) -> None:
    """Write NSSharingContentScopeItem (0) into AppKit out-parameter (^q). Module-level — not on NSObject."""
    if scope is None:
        return
    try:
        scope[0] = value
        return
    except Exception as exc:
        _share_log(logging.DEBUG, "sharingContentScope scope[0]: %s", exc)
    try:
        import ctypes

        ptr = int(scope) if hasattr(scope, "__index__") else scope
        ctypes.cast(ptr, ctypes.POINTER(ctypes.c_long))[0] = value
    except Exception as exc:
        _share_log(logging.DEBUG, "sharingContentScope ctypes: %s", exc)


def _macos_register_sharing_service_delegate_metadata(delegate_cls) -> None:
    """Tell PyObjC that argument 4 is out-pointer (^q) so scope[0] works (no ObjCPointerWarning)."""
    try:
        import objc

        scope_out_type = objc._C_OUT + objc._C_PTR + objc._C_LNG
        meta = dict(arguments={4: dict(type=scope_out_type)})
        sel = b"sharingService:sourceWindowForShareItems:sharingContentScope:"
        for cls_name in (delegate_cls.__name__.encode(), b"NSObject"):
            try:
                objc.registerMetaDataForSelector(cls_name, sel, meta)
            except Exception:
                pass
    except Exception as exc:
        _share_log(logging.DEBUG, "sharing delegate metadata registration: %s", exc)


def _get_macos_sharing_service_delegate_class():
    """NSSharingServiceDelegate — AirDrop needs source NSWindow from Qt (Mail does not)."""
    global _macos_sharing_service_delegate_cls
    if _macos_sharing_service_delegate_cls is not None:
        return _macos_sharing_service_delegate_cls
    import objc
    from AppKit import NSMakeRect, NSObject, NSScreen

    class MacSharingServiceDelegate(NSObject):
        def initWithViewer_(self, viewer):
            self = objc.super(MacSharingServiceDelegate, self).init()
            if self is None:
                return None
            self._viewer = viewer
            return self

        def sharingService_sourceWindowForShareItems_sharingContentScope_(
            self, service, items, scope
        ):
            """Return NSWindow; set sharingContentScope or AirDrop gets ObjCPointerWarning (^q)."""
            _macos_write_sharing_content_scope(scope, 0)
            viewer = getattr(self, "_viewer", None)
            if viewer is None:
                return None
            try:
                win = viewer._macos_share_ns_window()
                if win is None:
                    _share_log(logging.WARNING, "AirDrop delegate: no source NSWindow")
                return win
            except Exception as exc:
                _share_log(logging.DEBUG, "sourceWindow delegate: %s", exc)
                return None

        def sharingService_willShareItems_(self, service, items):
            _share_log(logging.INFO, "sharing service will share items: %s", service)

        def sharingService_sourceFrameOnScreenForShareItem_(self, service, item):
            viewer = getattr(self, "_viewer", None)
            btn = getattr(viewer, "share_bottom_button", None) if viewer else None
            if btn is None:
                return NSMakeRect(0, 0, 1, 1)
            try:
                screen = NSScreen.mainScreen()
                if screen is None:
                    return NSMakeRect(0, 0, max(1, btn.width()), max(1, btn.height()))
                frame = screen.frame()
                top_left = btn.mapToGlobal(QPoint(0, 0))
                w = max(1, btn.width())
                h = max(1, btn.height())
                x = float(top_left.x())
                y = float(frame.size.height) - float(top_left.y()) - h
                return NSMakeRect(x, y, w, h)
            except Exception:
                return NSMakeRect(0, 0, max(1, btn.width()), max(1, btn.height()))

        def sharingService_didShareItems_(self, service, items):
            viewer = getattr(self, "_viewer", None)
            if viewer is not None:
                viewer._macos_share_airdrop_completed = True
                _share_log(logging.INFO, "sharing service shared items successfully")
                QTimer.singleShot(0, viewer._macos_cleanup_share_temp)
                QTimer.singleShot(0, lambda: viewer._macos_share_end_picker_session("service_success"))

        def sharingService_didFailToShareItems_error_(self, service, items, error):
            viewer = getattr(self, "_viewer", None)
            if viewer is not None:
                viewer._macos_share_airdrop_completed = True
                _share_log(logging.WARNING, "sharing service failed to share items: %s", error)
                QTimer.singleShot(0, viewer._macos_cleanup_share_temp)
                QTimer.singleShot(0, lambda: viewer._macos_share_end_picker_session("service_fail"))

    _macos_register_sharing_service_delegate_metadata(MacSharingServiceDelegate)
    _macos_sharing_service_delegate_cls = MacSharingServiceDelegate
    return MacSharingServiceDelegate


def _get_macos_share_picker_delegate_class():
    """Lazy NSObject delegate so NSSharingServicePicker can populate and we resume Qt filters on dismiss."""
    global _macos_share_picker_delegate_cls
    if _macos_share_picker_delegate_cls is not None:
        return _macos_share_picker_delegate_cls
    import objc
    from AppKit import NSObject

    class MacSharePickerDelegate(NSObject):
        def initWithViewer_(self, viewer):
            self = objc.super(MacSharePickerDelegate, self).init()
            if self is None:
                return None
            self._viewer = viewer
            return self

        def sharingServicePicker_sharingServicesForItems_proposedSharingServices_(
            self, picker, items, proposed
        ):
            viewer = getattr(self, "_viewer", None)
            cached = getattr(viewer, "_macos_share_cached_services", None) if viewer else None
            if cached:
                try:
                    n = len(cached)
                except Exception:
                    n = -1
                _share_log(logging.INFO, "picker delegate: returning %d cached service(s)", n)
                return cached
            try:
                n = len(proposed or [])
            except Exception:
                n = -1
            _share_log(logging.INFO, "picker delegate: returning %d proposed service(s)", n)
            return proposed

        def sharingServicePicker_delegateForSharingService_(self, picker, service):
            viewer = getattr(self, "_viewer", None)
            if viewer is None:
                return None
            try:
                delegate_cls = _get_macos_sharing_service_delegate_class()
                delegate = delegate_cls.alloc().initWithViewer_(viewer)
                # Keep reference to prevent GC
                viewer._macos_active_service_delegate = delegate
                return delegate
            except Exception as exc:
                _share_log(logging.WARNING, "failed to create service delegate: %s", exc)
                return None

        def sharingServicePicker_didChooseSharingService_(self, picker, service):
            viewer = getattr(self, "_viewer", None)
            if viewer is not None:
                _share_log(logging.INFO, "picker didChooseSharingService: %s", service)
                QTimer.singleShot(0, viewer._macos_cleanup_share_temp)
                reason = "picker_cancel" if service is None else "picker_chose"
                QTimer.singleShot(0, lambda r=reason: viewer._macos_share_end_picker_session(r))
            return None

    _macos_share_picker_delegate_cls = MacSharePickerDelegate
    return MacSharePickerDelegate


def _activate_macos_foreground_for_share() -> None:
    """Bring app forward for NSSharingService (AirDrop panel needs a key window)."""
    if sys.platform != "darwin":
        return
    try:
        import objc

        ns_app = objc.lookUpClass("NSApplication").sharedApplication()
        if ns_app is not None:
            ns_app.setActivationPolicy_(0)
            ns_app.activateIgnoringOtherApps_(True)
    except Exception as exc:
        _share_log(logging.DEBUG, "share foreground activate: %s", exc)


def _activate_macos_foreground_app() -> None:
    """Opt-in NSApplication foreground (RAWVIEWER_MACOS_FORCE_FOREGROUND=1).

    Default off: v2.1 dev never needed this; brute-force activation can fight AppKit
    sheets (e.g. NSSharingServicePicker). Use Qt raise/activateWindow in dialogs instead.
    """
    if sys.platform != "darwin" or not _env_true("RAWVIEWER_MACOS_FORCE_FOREGROUND"):
        return
    try:
        import objc

        ns_app = objc.lookUpClass("NSApplication").sharedApplication()
        if ns_app is not None:
            ns_app.setActivationPolicy_(0)
            ns_app.activateIgnoringOtherApps_(True)
            _share_log(logging.DEBUG, "NSApplication activateIgnoringOtherApps OK")
    except Exception as exc:
        _share_log(logging.WARNING, "NSApplication foreground activation failed: %s", exc)


def _applescript_escape(value: str) -> str:
    return (value or "").replace("\\", "\\\\").replace('"', '\\"')


def _run_applescript(script: str) -> str:
    """Run AppleScript; return stdout on success, empty string on cancel/error."""
    import subprocess

    try:
        proc = subprocess.run(
            ["osascript", "-e", script],
            capture_output=True,
            text=True,
            timeout=3600,
        )
    except (OSError, subprocess.TimeoutExpired):
        return ""
    if proc.returncode != 0:
        return ""
    return (proc.stdout or "").strip()


def _macos_try_force_dark_titlebar():
    """
    Best-effort: request Dark Aqua appearance on macOS so the native title bar
    matches our dark UI. This uses the Objective-C runtime via ctypes to avoid
    adding PyObjC as a dependency.
    """
    if sys.platform != "darwin":
        return False
    try:
        import ctypes
        import ctypes.util

        objc_path = ctypes.util.find_library("objc") or "/usr/lib/libobjc.A.dylib"
        appkit_path = ctypes.util.find_library("AppKit") or "/System/Library/Frameworks/AppKit.framework/AppKit"
        objc = ctypes.cdll.LoadLibrary(objc_path)
        ctypes.cdll.LoadLibrary(appkit_path)

        objc.objc_getClass.restype = ctypes.c_void_p
        objc.objc_getClass.argtypes = [ctypes.c_char_p]
        objc.sel_registerName.restype = ctypes.c_void_p
        objc.sel_registerName.argtypes = [ctypes.c_char_p]

        # On arm64, objc_msgSend must be cast to an appropriately-typed function pointer.
        _msg_obj = ctypes.CFUNCTYPE(ctypes.c_void_p, ctypes.c_void_p, ctypes.c_void_p)(("objc_msgSend", objc))
        _msg_obj_charp = ctypes.CFUNCTYPE(ctypes.c_void_p, ctypes.c_void_p, ctypes.c_void_p, ctypes.c_char_p)(("objc_msgSend", objc))
        _msg_void_obj = ctypes.CFUNCTYPE(None, ctypes.c_void_p, ctypes.c_void_p, ctypes.c_void_p)(("objc_msgSend", objc))

        def cls(name: str) -> int:
            return int(objc.objc_getClass(name.encode("utf-8")))

        def sel(name: str) -> int:
            return int(objc.sel_registerName(name.encode("utf-8")))

        NSString = cls("NSString")
        NSAppearance = cls("NSAppearance")
        NSApplication = cls("NSApplication")

        # name = "NSAppearanceNameDarkAqua"
        name_str = _msg_obj_charp(NSString, sel("stringWithUTF8String:"), b"NSAppearanceNameDarkAqua")
        appearance = _msg_obj(NSAppearance, sel("appearanceNamed:"), name_str)

        app = _msg_obj(NSApplication, sel("sharedApplication"))
        if not app or not appearance:
            return False

        _msg_void_obj(app, sel("setAppearance:"), appearance)
        return True
    except Exception:
        # Never fail startup due to cosmetic integration.
        return False


def _macos_try_force_dark_titlebar_for_window(widget):
    """
    Best-effort: set Dark Aqua on the NSWindow backing a Qt widget.
    This is more reliable than setting NSApp appearance alone for the title bar.
    """
    if sys.platform != "darwin":
        return False
    if widget is None:
        return False
    try:
        import ctypes
        import ctypes.util

        objc_path = ctypes.util.find_library("objc") or "/usr/lib/libobjc.A.dylib"
        appkit_path = ctypes.util.find_library("AppKit") or "/System/Library/Frameworks/AppKit.framework/AppKit"
        objc = ctypes.cdll.LoadLibrary(objc_path)
        ctypes.cdll.LoadLibrary(appkit_path)

        objc.objc_getClass.restype = ctypes.c_void_p
        objc.objc_getClass.argtypes = [ctypes.c_char_p]
        objc.sel_registerName.restype = ctypes.c_void_p
        objc.sel_registerName.argtypes = [ctypes.c_char_p]

        _msg_obj = ctypes.CFUNCTYPE(ctypes.c_void_p, ctypes.c_void_p, ctypes.c_void_p)(("objc_msgSend", objc))
        _msg_obj_charp = ctypes.CFUNCTYPE(
            ctypes.c_void_p, ctypes.c_void_p, ctypes.c_void_p, ctypes.c_char_p
        )(("objc_msgSend", objc))
        _msg_void_obj = ctypes.CFUNCTYPE(None, ctypes.c_void_p, ctypes.c_void_p, ctypes.c_void_p)(("objc_msgSend", objc))
        _msg_void_bool = ctypes.CFUNCTYPE(None, ctypes.c_void_p, ctypes.c_void_p, ctypes.c_bool)(("objc_msgSend", objc))
        _msg_void_int = ctypes.CFUNCTYPE(None, ctypes.c_void_p, ctypes.c_void_p, ctypes.c_int)(("objc_msgSend", objc))
        _msg_obj_4d = ctypes.CFUNCTYPE(
            ctypes.c_void_p,
            ctypes.c_void_p,
            ctypes.c_void_p,
            ctypes.c_double,
            ctypes.c_double,
            ctypes.c_double,
            ctypes.c_double,
        )(("objc_msgSend", objc))

        def cls(name: str) -> int:
            return int(objc.objc_getClass(name.encode("utf-8")))

        def sel(name: str) -> int:
            return int(objc.sel_registerName(name.encode("utf-8")))

        NSString = cls("NSString")
        NSAppearance = cls("NSAppearance")
        NSColor = cls("NSColor")

        # Obtain NSView* from Qt widget. On macOS, QWidget.winId() is a pointer.
        view_ptr = int(widget.winId())
        if not view_ptr:
            return False

        window_ptr = _msg_obj(ctypes.c_void_p(view_ptr), sel("window"))
        window_ptr = int(window_ptr or 0)
        if not window_ptr:
            return False

        name_str = _msg_obj_charp(NSString, sel("stringWithUTF8String:"), b"NSAppearanceNameDarkAqua")
        appearance = _msg_obj(NSAppearance, sel("appearanceNamed:"), name_str)
        if not appearance:
            return False

        _msg_void_obj(ctypes.c_void_p(window_ptr), sel("setAppearance:"), appearance)

        return True
    except Exception:
        return False
